}

const ACTION_CONFIG = {
  delete_all_clients: {
    title: 'Apagar todos os clientes',
    description: 'Esta a├â┬º├â┬úo ir├â┬í excluir permanentemente TODOS os clientes (role "cliente"), incluindo seus agendamentos, pets, avalia├â┬º├â┬Áes, fotos e dados associados. Usu├â┬írios ADMIN, M├â┬ìDIA e DEV N├âãÆO ser├â┬úo afetados.',
