    confirmWord: 'COME├âÔÇíAR DO ZERO',
    icon: RotateCcw,
    buttonText: 'Resetar tudo',
  },
};

export function DangerZoneModal({ open, onOpenChange, action, onSuccess }: DangerZoneModalProps) {
  const config = ACTION_CONFIG[action];
  const Icon = config.icon;

  const [reason, setReason] = useState('');
  const [password, setPassword] = useState('');
  const [confirmText, setConfirmText] = useState('');
  const [loading, setLoading] = useState(false);

  const canSubmit = reason.trim().length >= 3 && password && confirmText === config.confirmWord;

  const handleSubmit = async () => {
    if (!canSubmit) return;
    setLoading(true);
    try {
      const response = await supabase.rpc('rpc_danger_zone' as any, {
        p_action: action, 
        p_reason: reason.trim(), 
        p_dev_password: password, 
        p_petshop_id: PETSHOP_ID
      });
      
      const data = response.data as any;
      const error = response.error;

      if (error) {
        toast.error(error.message || 'Erro ao executar ac├úo.');
      } else if (data?.error) {
        toast.error(data.error);
      } else {
        toast.success(data?.message || 'Ac├úo conclu├¡da com sucesso!');
        setReason('');
        setPassword('');
        setConfirmText('');
        onOpenChange(false);
        onSuccess?.();
      }
    } catch (err: any) {
      toast.error(err.message || 'Erro inesperado.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-md">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2 text-destructive">
            <AlertTriangle className="w-5 h-5" /> {config.title}
          </DialogTitle>
        </DialogHeader>
        <div className="space-y-4 mt-2">
          <div className="p-3 bg-destructive/10 rounded-lg text-sm text-destructive">
            <strong>├ó┼í┬á├»┬©┬Å ATEN├âÔÇí├âãÆO:</strong> {config.description}
          </div>
          <div className="space-y-2">
            <Label>Motivo *</Label>
            <Textarea
              value={reason}
              onChange={e => setReason(e.target.value)}
              placeholder="Descreva o motivo..."
              rows={2}
            />
          </div>
          <div className="space-y-2">
            <Label>Senha da conta DEV *</Label>
            <Input
              type="password"
              value={password}
              onChange={e => setPassword(e.target.value)}
              placeholder="Digite sua senha"
            />
          </div>
          <div className="space-y-2">
            <Label>
              Digite <span className="font-bold text-destructive">{config.confirmWord}</span> para confirmar
            </Label>
            <Input
              value={confirmText}
              onChange={e => setConfirmText(e.target.value)}
              placeholder={config.confirmWord}
              className="font-mono"
            />
          </div>
        </div>
        <DialogFooter className="flex-col sm:flex-row gap-2 mt-4">
          <Button variant="outline" onClick={() => onOpenChange(false)} disabled={loading}>
            Cancelar
          </Button>
          <Button
            variant="destructive"
            onClick={handleSubmit}
            disabled={loading || !canSubmit}
            className="gap-2"
          >
            <Icon className="w-4 h-4" />
            {loading ? 'Processando...' : config.buttonText}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

import { useEffect, useState, useRef } from 'react';
import { X } from 'lucide-react';
import { useAuth } from '@/contexts/AuthContext';
import { getNotifications, NotificationRow } from '@/services/notificationsService';
import { getNotificationConfig } from '@/lib/notificationTypes';
import { formatDistanceToNow } from 'date-fns';
import { ptBR } from 'date-fns/locale';

const SESSION_KEY = 'petcao_login_toast_shown';

export function LoginNotificationToast() {
  const { user, isAuthenticated } = useAuth();
  const [notification, setNotification] = useState<NotificationRow | null>(null);
  const [visible, setVisible] = useState(false);
  const [exiting, setExiting] = useState(false);
  const timerRef = useRef<ReturnType<typeof setTimeout>>();

  useEffect(() => {
    if (!isAuthenticated || !user?.id) return;

    // Only show once per session
    const shown = sessionStorage.getItem(SESSION_KEY);
    if (shown) return;

    const fetchLatest = async () => {
      try {
        const all = await getNotifications(user.id);
        const unread = all.filter(n => !n.read_at);
        if (unread.length > 0) {
          setNotification(unread[0]);
          sessionStorage.setItem(SESSION_KEY, 'true');
          // Small delay for page load
          setTimeout(() => setVisible(true), 800);
        }
      } catch {}
    };

    fetchLatest();
  }, [isAuthenticated, user?.id]);

  useEffect(() => {
    if (!visible) return;
    timerRef.current = setTimeout(() => dismiss(), 6000);
    return () => { if (timerRef.current) clearTimeout(timerRef.current); };
  }, [visible]);

  const dismiss = () => {
    setExiting(true);
    setTimeout(() => { setVisible(false); setNotification(null); }, 300);
  };

  if (!notification || !visible) return null;

  const config = getNotificationConfig(notification.type);
  const Icon = config.icon;

  return (
    <div className="fixed top-4 left-1/2 -translate-x-1/2 z-[100] w-[calc(100%-2rem)] max-w-md pointer-events-auto">
      <div
        className={`
          bg-card/95 backdrop-blur-2xl border border-border/50 rounded-2xl shadow-2xl shadow-black/10
          p-4 flex items-start gap-3
          transition-all duration-300 ease-out
          ${exiting ? 'opacity-0 -translate-y-4 scale-95' : 'opacity-100 translate-y-0 scale-100'}
          animate-in slide-in-from-top-4 fade-in duration-500
        `}
      >
        <div className={`w-10 h-10 rounded-xl ${config.bgClass} flex items-center justify-center shrink-0`}>
          <Icon className={`w-5 h-5 ${config.colorClass}`} />
        </div>
        <div className="flex-1 min-w-0">
          <p className="text-sm font-semibold text-foreground">{notification.title}</p>
          {notification.description && (
            <p className="text-[13px] text-muted-foreground mt-0.5 line-clamp-2">{notification.description}</p>
          )}
          <p className="text-[11px] text-muted-foreground/50 mt-1">
            {formatDistanceToNow(new Date(notification.created_at), { addSuffix: true, locale: ptBR })}
          </p>
        </div>
        <button
          onClick={dismiss}
          className="p-1.5 rounded-lg text-muted-foreground hover:text-foreground hover:bg-muted/50 transition-colors shrink-0"
        >
          <X className="w-4 h-4" />
        </button>
      </div>
    </div>
  );
}

