];

const SERVICES = ['Banho', 'Tosa', 'Banho + Tosa', 'Tosa higi├¬nica', 'Hidrata├º├úo'];
const TIMES = ['08:00', '09:00', '10:00', '11:00', '13:00', '14:00', '15:00', '16:00', '17:00'];
const STATUSES = ['confirmado', 'confirmado', 'pendente', 'realizado', 'realizado', 'realizado'];
const PAYMENT_METHODS = ['pix', 'cartao', 'dinheiro', 'pix'];

function generateDemoData(config: DemoConfig): DemoData {
  const today = new Date();
  const clientCount = Math.min(config.clients, CLIENT_POOL.length);
  const petCount = Math.min(config.pets, PET_POOL.length);
  const aptCount = config.appointments;

  const clients = CLIENT_POOL.slice(0, clientCount);
  const pets = PET_POOL.slice(0, petCount).map((p, i) => ({ ...p, ownerIndex: i % clientCount }));

  const appointments: DemoData['appointments'] = [];
  let totalRevenue = 0;
  let totalPending = 0;

  for (let i = 0; i < aptCount; i++) {
    const pet = pets[i % petCount];
    const service = SERVICES[i % SERVICES.length];
    const dayOffset = i < 3 ? 0 : i < 5 ? 1 : -(i - 4);
    const date = format(dayOffset >= 0 ? addDays(today, dayOffset) : subDays(today, Math.abs(dayOffset)), 'yyyy-MM-dd');
    const time = TIMES[i % TIMES.length];
    const status = STATUSES[i % STATUSES.length];
    const price = [60, 80, 100, 120, 150][i % 5];
    const isPaid = status === 'realizado' || (status === 'confirmado' && i % 3 === 0);
    const paymentStatus = isPaid ? 'pago' : 'pendente';
    const paymentMethod = isPaid ? PAYMENT_METHODS[i % PAYMENT_METHODS.length] : 'pix';

    if (isPaid) totalRevenue += price;
    else totalPending += price;

    appointments.push({
      service_name: service,
      petName: pet.name,
      date,
      time,
      status,
      price,
      payment_status: paymentStatus,
      payment_method: paymentMethod,
    });
  }

  // Override revenue if user set a custom value
  if (config.revenue !== DEFAULT_DEMO_CONFIG.revenue) {
    totalRevenue = config.revenue;
  }

  // Generate ProfileRow-shaped data
  const profileRows: ProfileRow[] = clients.map((c, i) => ({
    id: `demo-profile-${i}`,
    user_id: `demo-user-${i}`,
    name: c.name,
    phone: c.phone,
    avatar_url: null,
    active: true,
    petshop_id: PETSHOP_ID,
    created_at: format(subDays(today, Math.floor(Math.random() * 30)), "yyyy-MM-dd'T'HH:mm:ss"),
    updated_at: format(today, "yyyy-MM-dd'T'HH:mm:ss"),
  }));

  // Generate AppointmentRow-shaped data
  const appointmentRows: AppointmentRow[] = appointments.map((a, i) => {
    const ownerIdx = pets[i % petCount].ownerIndex;
    return {
      id: `demo-apt-${i}`,
      petshop_id: PETSHOP_ID,
      customer_id: `demo-user-${ownerIdx}`,
      service_id: null,
      service_name: a.service_name,
      date: a.date,
      time: a.time,
      status: a.status,
      price: a.price,
      payment_status: a.payment_status,
      payment_method: a.payment_method,
      payment_amount: a.payment_status === 'pago' ? a.price : null,
      completed_at: a.status === 'realizado' ? format(today, "yyyy-MM-dd'T'HH:mm:ss") : null,
      cancel_reason: null,
      notes: '',
      origin: 'demo',
      created_at: format(subDays(today, 1), "yyyy-MM-dd'T'HH:mm:ss"),
      updated_at: format(today, "yyyy-MM-dd'T'HH:mm:ss"),
      customer_name: clients[ownerIdx].name,
      customer_phone: clients[ownerIdx].phone,
      pets: [{
        id: `demo-pet-${i}`,
        appointment_id: `demo-apt-${i}`,
        pet_id: `demo-pet-ref-${i % petCount}`,
        pet_name: a.petName,
        pet_size: pets[i % petCount].size,
        pet_breed: pets[i % petCount].breed,
      }],
    };
  });

  return {
    clients,
    pets,
    appointments,
    revenue: totalRevenue,
    pending: totalPending,
    profileRows,
    appointmentRows,
  };
}

export function TestModesProvider({ children }: { children: ReactNode }) {
  const [proModeActive, setProModeActive] = useState(false);
  const [basicModeActive, setBasicModeActive] = useState(false);
  const [clientModeActive, setClientModeActive] = useState(false);
  const [demoModeActive, setDemoModeActive] = useState(false);
  const [demoData, setDemoData] = useState<DemoData | null>(null);
  const [demoConfig, setDemoConfig] = useState<DemoConfig>(DEFAULT_DEMO_CONFIG);

  const toggleProMode = useCallback(() => {
    setProModeActive(prev => !prev);
    setBasicModeActive(false);
  }, []);

  const toggleBasicMode = useCallback(() => {
    setBasicModeActive(prev => !prev);
    setProModeActive(false);
  }, []);

  const toggleClientMode = useCallback(() => setClientModeActive(prev => !prev), []);

  const toggleDemoMode = useCallback(() => {
    setDemoModeActive(prev => {
      if (!prev) {
        setDemoData(generateDemoData(demoConfig));
      } else {
        setDemoData(null);
      }
      return !prev;
    });
  }, [demoConfig]);

  const regenerateDemoData = useCallback(() => {
    if (demoModeActive) {
      setDemoData(generateDemoData(demoConfig));
    }
  }, [demoModeActive, demoConfig]);

  const clearDemoData = useCallback(() => {
    setDemoModeActive(false);
    setDemoData(null);
  }, []);

  const activeModes = useMemo(() => {
    const modes: string[] = [];
    if (proModeActive) modes.push('PRO');
    if (basicModeActive) modes.push('B├ísico');
    if (clientModeActive) modes.push('Cliente');
    if (demoModeActive) modes.push('Demo');
    return modes;
  }, [proModeActive, basicModeActive, clientModeActive, demoModeActive]);

  const anyModeActive = activeModes.length > 0;

  return (
    <TestModesContext.Provider value={{
      proModeActive, toggleProMode,
      basicModeActive, toggleBasicMode,
      clientModeActive, toggleClientMode,
      demoModeActive, toggleDemoMode,
      demoData, clearDemoData,
      demoConfig, setDemoConfig, regenerateDemoData,
      anyModeActive, activeModes,
    }}>
      {children}
    </TestModesContext.Provider>
  );
}

export function useTestModes() {
  const context = useContext(TestModesContext);
  if (!context) throw new Error('useTestModes must be used within TestModesProvider');
  return context;
}

import { useCallback } from 'react';
import { usePetshop } from '@/contexts/PetshopContext';
import { PetshopSettings, DateOverride, WHATSAPP_NUMBER } from '@/lib/constants';

export interface WeeklySchedule {
  dom: boolean;
  seg: boolean;
  ter: boolean;
  qua: boolean;
  qui: boolean;
  sex: boolean;
  sab: boolean;
}

export interface OpeningHours {
  openTime: string;
  closeTime: string;
}

export interface SocialLink {
  key: string;
  label: string;
  url: string;
  enabled: boolean;
}

export interface ShopAddress {
  address: string;
  phone: string;
  whatsapp: string;
}

export interface DisplayLimits {
  maxPhotos: number;
  maxReviews: number;
  moderationPageSizePhotos: number;
  moderationPageSizeReviews: number;
  userUploadPhotoDailyLimit: number;
}

export interface LocationSettings {
  latitude: string;
  longitude: string;
  zoom: number;
}

const DAY_MAP: (keyof WeeklySchedule)[] = ['dom', 'seg', 'ter', 'qua', 'qui', 'sex', 'sab'];
const DAY_KEYS_TO_ABBR: Record<string, keyof WeeklySchedule> = {
  dom: 'dom', seg: 'seg', ter: 'ter', qua: 'qua', qui: 'qui', sex: 'sex', sab: 'sab',
};

function openDaysToSchedule(openDays: string[]): WeeklySchedule {
  const schedule: WeeklySchedule = { dom: false, seg: false, ter: false, qua: false, qui: false, sex: false, sab: false };
  openDays.forEach(d => {
    const key = DAY_KEYS_TO_ABBR[d];
    if (key) schedule[key] = true;
  });
  return schedule;
}

function scheduleToOpenDays(schedule: WeeklySchedule): string[] {
  return DAY_MAP.filter(k => schedule[k]);
}

const SOCIAL_LABELS: Record<string, string> = {
  instagram: 'Instagram', tiktok: 'TikTok', facebook: 'Facebook',
  youtube: 'YouTube', whatsapp: 'WhatsApp', site: 'Site',
};

function settingsToSocialLinks(settings: PetshopSettings): SocialLink[] {
  const keys = ['instagram', 'tiktok', 'facebook', 'youtube', 'whatsapp', 'site'];
  return keys.map(key => ({
    key,
    label: SOCIAL_LABELS[key] || key,
    url: settings.social_links.links[`${key}_url`] || (key === 'whatsapp' ? `https://wa.me/${WHATSAPP_NUMBER}` : ''),
    enabled: !!settings.social_links.enabled[key],
  }));
}

function socialLinksToSettings(links: SocialLink[]): PetshopSettings['social_links'] {
  const enabled: Record<string, boolean> = {};
  const linksMap: Record<string, string> = {};
  links.forEach(l => {
    enabled[l.key] = l.enabled;
    linksMap[`${l.key}_url`] = l.url;
  });
  return { enabled, links: linksMap };
}

export function useConfig() {
  const { petshop, settings, updateSettings, updatePetshop } = usePetshop();

  const weeklySchedule = openDaysToSchedule(settings.openDaysDefault);
  const dateOverrides = settings.dateOverrides || [];
  const openingHours: OpeningHours = { openTime: settings.openTimeDefault, closeTime: settings.closeTimeDefault };
  const socialLinks = settingsToSocialLinks(settings);
  const shopAddress: ShopAddress = {
    address: petshop?.address || '',
    phone: petshop?.phone || '',
    whatsapp: WHATSAPP_NUMBER,
  };
  const displayLimits: DisplayLimits = {
    maxPhotos: settings.limiteHomeFotos,
    maxReviews: settings.limiteHomeAvaliacoes,
    moderationPageSizePhotos: settings.moderationPageSizePhotos,
    moderationPageSizeReviews: settings.moderationPageSizeReviews,
    userUploadPhotoDailyLimit: settings.userUploadPhotoDailyLimit,
  };
  const locationSettings: LocationSettings = {
    latitude: String(petshop?.latitude || '-23.404187'),
    longitude: String(petshop?.longitude || '-46.863688'),
    zoom: settings.locationZoom,
  };
  const appointmentInterval = settings.slotIntervalMinutes;

  const setWeeklySchedule = useCallback(async (updater: WeeklySchedule | ((prev: WeeklySchedule) => WeeklySchedule)) => {
    const newSchedule = typeof updater === 'function' ? updater(weeklySchedule) : updater;
    await updateSettings({ openDaysDefault: scheduleToOpenDays(newSchedule) });
  }, [weeklySchedule, updateSettings]);

  const setOpeningHours = useCallback(async (hours: OpeningHours) => {
    await updateSettings({ openTimeDefault: hours.openTime, closeTimeDefault: hours.closeTime });
  }, [updateSettings]);

  const setSocialLinks = useCallback(async (links: SocialLink[]) => {
    await updateSettings({ social_links: socialLinksToSettings(links) });
  }, [updateSettings]);

  const setShopAddress = useCallback(async (addr: ShopAddress) => {
    await updatePetshop({ address: addr.address, phone: addr.phone });
  }, [updatePetshop]);

  const setDisplayLimits = useCallback(async (limits: DisplayLimits) => {
    await updateSettings({
      limiteHomeFotos: limits.maxPhotos,
      limiteHomeAvaliacoes: limits.maxReviews,
      moderationPageSizePhotos: limits.moderationPageSizePhotos,
      moderationPageSizeReviews: limits.moderationPageSizeReviews,
      userUploadPhotoDailyLimit: limits.userUploadPhotoDailyLimit,
    });
  }, [updateSettings]);

  const setLocationSettings = useCallback(async (loc: LocationSettings) => {
    await Promise.all([
      updatePetshop({ latitude: Number(loc.latitude), longitude: Number(loc.longitude) }),
      updateSettings({ locationZoom: loc.zoom }),
    ]);
  }, [updatePetshop, updateSettings]);

  const setAppointmentInterval = useCallback(async (interval: number) => {
    await updateSettings({ slotIntervalMinutes: interval });
  }, [updateSettings]);

  const addDateOverride = useCallback(async (override: DateOverride) => {
    const filtered = dateOverrides.filter(o => o.date !== override.date);
    await updateSettings({ dateOverrides: [...filtered, override] });
  }, [dateOverrides, updateSettings]);

  const removeDateOverride = useCallback(async (date: string) => {
    await updateSettings({ dateOverrides: dateOverrides.filter(o => o.date !== date) });
  }, [dateOverrides, updateSettings]);

  const isOpenOnDate = useCallback((date: Date): boolean => {
    const dateStr = date.toISOString().split('T')[0];
    const override = dateOverrides.find(o => o.date === dateStr);
    if (override) return override.isOpen;
    const dayIndex = date.getDay();
    const dayKey = DAY_MAP[dayIndex];
    return weeklySchedule[dayKey];
  }, [weeklySchedule, dateOverrides]);

  return {
    weeklySchedule, setWeeklySchedule,
    dateOverrides, addDateOverride, removeDateOverride,
    openingHours, setOpeningHours,
    socialLinks, setSocialLinks,
    shopAddress, setShopAddress,
    displayLimits, setDisplayLimits,
    locationSettings, setLocationSettings,
    appointmentInterval, setAppointmentInterval,
    isOpenOnDate,
  };
}

import { useState, useEffect, useCallback, useRef } from 'react';
import { supabase } from '@/lib/supabase';

/* ├óÔÇØÔé¼├óÔÇØÔé¼├óÔÇØÔé¼ Types ├óÔÇØÔé¼├óÔÇØÔé¼├óÔÇØÔé¼ */
export interface ApiRequest {
  id: string;
  method: string;
  url: string;
  status: number;
  duration: number;
  timestamp: Date;
}

export interface JsError {
  id: string;
  message: string;
  source: string;
  line: number;
  col: number;
  timestamp: Date;
}

export interface SystemMetrics {
  cpuPercent: number;
  memoryUsedMB: number;
  memoryTotalMB: number;
  rpm: number;
  totalRows: number;
  activeUsers: number;
  totalAppointments: number;
  tableCounts: Record<string, number>;
}

export interface WebhookStatus {
  name: string;
  status: 'online' | 'offline' | 'error';
  lastCall: Date | null;
  responseTime: number | null;
}

export interface JobItem {
  id: string;
  type: string;
  status: 'pending' | 'running' | 'done' | 'failed';
  duration: number | null;
  timestamp: Date;
}

export interface BackendLog {
  id: string;
  level: 'INFO' | 'WARN' | 'ERROR';
  message: string;
  timestamp: Date;
}

export interface DbStatus {
  connected: boolean;
  responseTime: number | null;
  activeConnections: number;
  totalRows: number;
  tableCounts: Record<string, number>;
}

export interface StorageBucket {
  name: string;
  public: boolean;
}

export interface FeatureFlag {
  key: string;
  enabled: boolean;
}

/* ├óÔÇØÔé¼├óÔÇØÔé¼├óÔÇØÔé¼ Hook ├óÔÇØÔé¼├óÔÇØÔé¼├óÔÇØÔé¼ */
export function useDevMonitor() {
  const [apiRequests, setApiRequests] = useState<ApiRequest[]>([]);
  const [jsErrors, setJsErrors] = useState<JsError[]>([]);
  const [metrics, setMetrics] = useState<SystemMetrics>({
    cpuPercent: 0, memoryUsedMB: 0, memoryTotalMB: 4096, rpm: 0,
    totalRows: 0, activeUsers: 0, totalAppointments: 0, tableCounts: {},
  });
  const [webhooks, setWebhooks] = useState<WebhookStatus[]>([]);
  const [jobs, setJobs] = useState<JobItem[]>([]);
  const [logs, setLogs] = useState<BackendLog[]>([]);
  const [dbStatus, setDbStatus] = useState<DbStatus>({ connected: false, responseTime: null, activeConnections: 0, totalRows: 0, tableCounts: {} });
  const [storageBuckets, setStorageBuckets] = useState<StorageBucket[]>([]);
  const [featureFlags, setFeatureFlags] = useState<FeatureFlag[]>([]);
  const [backendLoading, setBackendLoading] = useState(false);
  const requestCountRef = useRef(0);
  const idCounter = useRef(0);

  const genId = () => `dm-${++idCounter.current}-${Date.now()}`;
  const mkLog = (level: BackendLog['level'], message: string): BackendLog => ({ id: genId(), level, message, timestamp: new Date() });

  /* ├óÔÇØÔé¼├óÔÇØÔé¼ Intercept fetch ├óÔÇØÔé¼├óÔÇØÔé¼ */
  useEffect(() => {
    const originalFetch = window.fetch;
    window.fetch = async (...args) => {
      const start = performance.now();
      const url = typeof args[0] === 'string' ? args[0] : (args[0] as Request).url;
      const method = (args[1]?.method || 'GET').toUpperCase();
      requestCountRef.current++;
      try {
        const res = await originalFetch(...args);
        const duration = Math.round(performance.now() - start);
        setApiRequests(prev => [{
          id: genId(), method, url, status: res.status, duration, timestamp: new Date()
        }, ...prev].slice(0, 200));
        if (res.status >= 500) {
          setLogs(prev => [mkLog('ERROR', `${method} ${url} ├óÔÇáÔÇÖ ${res.status} (${duration}ms)`), ...prev].slice(0, 500));
        } else if (res.status >= 400) {
          setLogs(prev => [mkLog('WARN', `${method} ${url} ├óÔÇáÔÇÖ ${res.status} (${duration}ms)`), ...prev].slice(0, 500));
        }
        return res;
      } catch (err) {
        const duration = Math.round(performance.now() - start);
        setApiRequests(prev => [{
          id: genId(), method, url, status: 0, duration, timestamp: new Date()
        }, ...prev].slice(0, 200));
        setLogs(prev => [mkLog('ERROR', `${method} ${url} ├óÔÇáÔÇÖ NETWORK ERROR (${duration}ms)`), ...prev].slice(0, 500));
        throw err;
      }
    };
    return () => { window.fetch = originalFetch; };
  }, []);

  /* ├óÔÇØÔé¼├óÔÇØÔé¼ JS errors ├óÔÇØÔé¼├óÔÇØÔé¼ */
  useEffect(() => {
    const handler = (e: ErrorEvent) => {
      setJsErrors(prev => [{
        id: genId(), message: e.message || 'Unknown error', source: e.filename || 'unknown',
        line: e.lineno || 0, col: e.colno || 0, timestamp: new Date()
      }, ...prev].slice(0, 100));
      setLogs(prev => [mkLog('ERROR', `[JS] ${e.message} at ${e.filename}:${e.lineno}`), ...prev].slice(0, 500));
    };
    const unhandled = (e: PromiseRejectionEvent) => {
      const msg = e.reason?.message || String(e.reason);
      setJsErrors(prev => [{
        id: genId(), message: msg, source: 'Promise', line: 0, col: 0, timestamp: new Date()
      }, ...prev].slice(0, 100));
      setLogs(prev => [mkLog('ERROR', `[Promise] ${msg}`), ...prev].slice(0, 500));
    };
    window.addEventListener('error', handler);
    window.addEventListener('unhandledrejection', unhandled);
    return () => {
      window.removeEventListener('error', handler);
      window.removeEventListener('unhandledrejection', unhandled);
    };
  }, []);

  /* ├óÔÇØÔé¼├óÔÇØÔé¼ Client-side metrics ticker (every 3s) ├óÔÇØÔé¼├óÔÇØÔé¼ */
  useEffect(() => {
    const tick = () => {
      const mem = (performance as any).memory;
      const usedMB = mem ? Math.round(mem.usedJSHeapSize / 1048576) : Math.round(50 + Math.random() * 80);
      const totalMB = mem ? Math.round(mem.jsHeapSizeLimit / 1048576) : 4096;
      setMetrics(prev => ({
        ...prev,
        cpuPercent: Math.round(10 + Math.random() * 25), // browser doesn't expose real CPU
        memoryUsedMB: usedMB,
        memoryTotalMB: totalMB,
        rpm: requestCountRef.current * 20,
      }));
      requestCountRef.current = 0;
    };
    tick();
    const id = setInterval(tick, 3000);
    return () => clearInterval(id);
  }, []);

  /* Ôû¼Ôû¼ Fetch real backend metrics directly (Free Plan Compatible) Ôû¼Ôû¼ */
  const fetchBackendMetrics = useCallback(async () => {
    setBackendLoading(true);
    const start = performance.now();
    try {
      // Direct queries to count rows using { count: 'exact', head: true } 
      // which is incredibly fast and avoids downloading rows.
      const [
        { count: profilesCount, error: err1 },
        { count: apptCount, error: err2 },
        { count: petsCount, error: err3 },
        { count: servicesCount, error: err4 }
      ] = await Promise.all([
        supabase.from('profiles').select('user_id', { count: 'exact', head: true }),
        supabase.from('appointments').select('id', { count: 'exact', head: true }),
        supabase.from('pets').select('id', { count: 'exact', head: true }),
        supabase.from('services').select('id', { count: 'exact', head: true })
      ]);

      // If the first query throws, we consider the DB offline or inaccessible
      if (err1) throw err1;

      const elapsed = Math.round(performance.now() - start);
      setLogs(prev => [mkLog('INFO', `Backend metrics OK (${elapsed}ms)`), ...prev].slice(0, 500));

      const tableCounts = {
        profiles: profilesCount || 0,
        appointments: apptCount || 0,
        pets: petsCount || 0,
        services: servicesCount || 0,
      };

      const totalRows = Object.values(tableCounts).reduce((a, b) => a + b, 0);

      // Update DB status with real data
      setDbStatus({
        connected: true,
        responseTime: elapsed,
        activeConnections: 1,
        totalRows,
        tableCounts,
      });

      // Update metrics with real row counts
      setMetrics(prev => ({
        ...prev,
        totalRows,
        activeUsers: profilesCount || 0,
        totalAppointments: apptCount || 0,
        tableCounts,
      }));

      // Webhooks, Jobs, Storage Buckets, Feature Flags are set to empty/mock 
      // because they require admin privileges or Edge Functions not available on free plan
      setWebhooks([]);
      setJobs([]);
      setStorageBuckets([{ name: 'pets', public: true }, { name: 'gallery', public: true }]);
      setFeatureFlags([{ key: 'dev_tools', enabled: true }]);

    } catch (err: any) {
      setLogs(prev => [mkLog('ERROR', `Backend metrics exception: ${err?.message || 'unknown'}`), ...prev].slice(0, 500));
      setDbStatus(prev => ({ ...prev, connected: false }));
    }
    setBackendLoading(false);
  }, []);

  // Fetch on mount and every 15s
  useEffect(() => {
    fetchBackendMetrics();
    const id = setInterval(fetchBackendMetrics, 15000);
    return () => clearInterval(id);
  }, [fetchBackendMetrics]);

  /* ├óÔÇØÔé¼├óÔÇØÔé¼ Initial log ├óÔÇØÔé¼├óÔÇØÔé¼ */
  useEffect(() => {
    setLogs(prev => [mkLog('INFO', 'Dev Monitor inicializado ├óÔé¼ÔÇØ conectado ao backend real'), ...prev]);
  }, []);

  const clearLogs = useCallback(() => setLogs([]), []);
  const clearErrors = useCallback(() => setJsErrors([]), []);
  const clearRequests = useCallback(() => setApiRequests([]), []);
  const refreshAll = useCallback(() => { fetchBackendMetrics(); }, [fetchBackendMetrics]);

  return {
    apiRequests, jsErrors, metrics, webhooks, jobs, logs, dbStatus,
    storageBuckets, featureFlags, backendLoading,
    clearLogs, clearErrors, clearRequests, refreshAll,
  };
}

import { useState, useEffect, useCallback } from 'react';

const STORAGE_KEY = 'petcao-sidebar-collapsed';

export function useSidebarCollapse() {
  const [collapsed, setCollapsed] = useState(() => {
    try {
      return localStorage.getItem(STORAGE_KEY) === 'true';
    } catch {
      return false;
    }
  });

  useEffect(() => {
    try {
      localStorage.setItem(STORAGE_KEY, String(collapsed));
    } catch {}
  }, [collapsed]);

  const toggle = useCallback(() => setCollapsed(prev => !prev), []);

  // Keyboard shortcut: Ctrl/Cmd + B
  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'b') {
        e.preventDefault();
        toggle();
      }
    };
    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, [toggle]);

  return { collapsed, setCollapsed, toggle };
}

